-- в”Ђв”Ђ Tine в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
UPDATE tools SET
  short_description = COALESCE($q$Tine is an open-source groupware, CRM and collaboration suite covering email, calendar, contacts, tasks and CRM, developed by German company Metaways Infosystems and released under the AGPLv3 license.$q$, short_description),
  pricing_model = COALESCE($q$open-source$q$, pricing_model),
  starting_price = COALESCE($q$Free (self-hosted); hosted plans from EUR 12.90/month$q$, starting_price),
  founded_year = COALESCE(2008, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Hamburg, Germany$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$German$q$]::text[],
  seo_title = COALESCE($q$Tine Groupware Review: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Tine is an open-source groupware and CRM suite with email, calendar and tasks. See Tine's pricing, self-hosting options and how it compares to alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Tine, previously called Tine 2.0, is an open-source business collaboration suite covering groupware, CRM and light ERP functionality, developed and maintained by German software company Metaways Infosystems GmbH, founded in Hamburg in 2001. The project began in 2007 out of discussions within the eGroupware open-source community; two Metaways-funded developers built an initial MySQL-backed implementation with access control lists and a new interface, and the first version launched on October 30, 2008. The name Tine 2.0 was originally a playful backronym for This is not eGroupWare, signaling that it was an independent rewrite rather than a fork of the earlier eGroupware project. The suite is released under the GNU Affero General Public License version 3 (AGPLv3), and unlike many commercial open-source products that hold back premium features behind a closed enterprise edition, Tine publishes the complete source code of all standard applications and features as open source, including the modules used in its Business Edition. Tine's server is written in PHP with a SQL database backend, and its client runs as a JavaScript single-page application in the browser. Core modules include email, shared calendars, address books, task management, file sync and share, time tracking and a built-in CRM, making it comparable to products like Zimbra, Zoho, or the Nextcloud groupware modules, but oriented toward organizations that want full source-code access and self-hosting control. Organizations can self-host Tine at no license cost, or subscribe to Metaways's hosted SaaS offering, which starts at roughly 12.90 euros per month for a small package of user accounts, email inboxes and storage, with additional users and storage billed incrementally. Commercial partners also offer paid support and maintenance for the self-hosted Business Edition. Note: this Tine is the open-source groupware and CRM suite from the tine20.org lineage, unrelated to any person or brand of the same name.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '13d8e1cf-dc46-4ceb-a3df-aaf2719813b1';

