-- в”Ђв”Ђ Tiny File Manager в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
UPDATE tools SET
  short_description = COALESCE($q$Tiny File Manager is a free, open-source, single-file PHP web-based file manager that lets you browse, upload, edit and manage files on a server through the browser without a database.$q$, short_description),
  pricing_model = COALESCE($q$open-source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2017, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Tiny File Manager: Free Open-Source PHP File Manager$q$, seo_title),
  seo_meta_description = COALESCE($q$Tiny File Manager is a free single-file PHP web file manager. See its features, GitHub project, code editor, and how it compares to other file managers.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Tiny File Manager is a free, open-source, web-based file manager built as a single PHP file, created by developer Prasath Mani and first published on GitHub on July 5, 2017. It has no database dependency and no complex installation process: a user copies the single tinyfilemanager.php file, renaming it is recommended for security, to a web server, and it immediately provides a browser-based interface for uploading, downloading, editing, deleting, renaming, copying, moving, previewing and compressing or extracting files and folders. As of mid-2026 the project has accumulated roughly six thousand stars on GitHub and is licensed under the GPL-3.0 open-source license, meaning it is free to use, modify and redistribute with no cost or vendor lock-in. Its most notable built-in feature is an embedded Cloud9-based code editor with syntax highlighting for more than 150 programming languages and over 35 color themes, letting developers or site administrators edit code files directly in the browser rather than downloading and re-uploading them. It also includes basic user authentication with configurable per-user permissions and folder access restrictions, support for more than 50 interface languages, and a responsive layout that works on desktop, tablet and mobile devices. Because it requires only PHP and no external services, Tiny File Manager is commonly used by developers and sysadmins as a lightweight alternative to full-featured commercial file management panels, or as an emergency file browser when SSH or FTP access is unavailable, on shared hosting, small VPS instances, or self-hosted home server setups such as those built with Docker. It has no formal company or pricing model behind it; it is maintained as a community open-source project on GitHub, distinct from unrelated similarly named tools like TinaCMS, which is a headless content management system.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '3f583e3e-2f7f-4949-b806-41aa6c8365bb';

