-- в”Ђв”Ђ Tiny Tiny RSS в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
UPDATE tools SET
  short_description = COALESCE($q$Tiny Tiny RSS (tt-rss) is a free, open-source, self-hosted web-based RSS and Atom feed reader and aggregator that lets users control their own news feeds instead of relying on a third-party service.$q$, short_description),
  pricing_model = COALESCE($q$open-source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2005, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Tiny Tiny RSS (tt-rss): Free Self-Hosted RSS Reader$q$, seo_title),
  seo_meta_description = COALESCE($q$Tiny Tiny RSS is a free, open-source, self-hosted RSS and Atom feed reader. See its features, plugins, Docker setup and community fork status.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Tiny Tiny RSS, commonly abbreviated tt-rss, is a free and open-source, self-hosted RSS and Atom feed reader and aggregator written in PHP, originally created by developer Andrew Dolgov starting in 2005. Unlike hosted feed readers such as Feedly or Inoreader, tt-rss runs entirely on infrastructure the user controls, typically deployed via Docker and Docker Compose, so the user's reading data and subscription list are never stored on a third party's servers. It is licensed under the GNU General Public License version 3 (GPLv3) and has long been one of the most widely deployed self-hosted RSS readers in the open-source and privacy-focused hosting community, commonly listed alongside alternatives like FreshRSS and Miniflux. Core features include support for RSS, Atom and other feed formats, OPML import and export for migrating subscriptions from other readers, customizable keyboard shortcuts for fast keyboard-driven reading, article sharing to social platforms, a plugin system for extending functionality, and an official Android client for reading feeds on mobile. In a significant change to the project, the original tt-rss.org site and its founder-led development were retired on November 1, 2025, and the project has continued as a community-run fork on GitHub, created by a long-time contributor on October 3, 2025, with a stated goal of continuing development without major breaking changes. Because it is entirely open source and free to self-host, tt-rss has no pricing plans or company behind it; anyone with a server capable of running PHP and a database can install it at no cost, making it a durable option for readers who want long-term control over their RSS consumption rather than depending on a commercial hosted service that could shut down or change its pricing.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'f00ab228-25cf-4d37-82c5-5df4bbab3062';

