-- в”Ђв”Ђ TinyFeed в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
UPDATE tools SET
  short_description = COALESCE($q$TinyFeed is a free, open-source command-line tool written in Go that generates a lightweight, static HTML webpage from a collection of RSS, Atom and JSON feeds.$q$, short_description),
  pricing_model = COALESCE($q$open-source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2023, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$TinyFeed: Free Open-Source Static Feed Reader CLI Tool$q$, seo_title),
  seo_meta_description = COALESCE($q$TinyFeed is a free, open-source Go CLI tool that turns RSS, Atom and JSON feeds into a lightweight static webpage. See its features and setup.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$TinyFeed is a free, open-source command-line tool built in Go by developer Sebastien Lovergne, published on GitHub under the handle TheBigRoomXXL starting in September 2023. Rather than functioning as a traditional interactive feed reader application, TinyFeed generates a single lightweight, static HTML webpage from a list of RSS, Atom and JSON feed URLs, using the open-source gofeed parsing library to support all three formats. The project grew out of frustration with existing feed reader options: its creator wanted to consume feeds the way one reads a message board, as a simple, chronologically ordered list of links, rather than through a heavier interactive reader interface with unread counts, folders and complex navigation. Because the output is a static page, TinyFeed sites are extremely lightweight, load quickly, and are fully accessible, and they can be customized with external stylesheets and templates, including built-in support for automatic dark and light themes based on system preference. TinyFeed also supports a daemon mode that periodically regenerates the output page on a schedule, so a self-hosted instance can be left running to always show current feed items without manual intervention. It is released under the MIT license and, as of mid-2026, has accumulated a few hundred stars on GitHub, making it a niche but actively used tool among developers and self-hosters who prefer minimalist, static tooling over heavier feed reader software. TinyFeed has no company or pricing model behind it, is entirely free to use, and should not be confused with the unrelated, much older and more feature-rich Tiny Tiny RSS project, despite the similar name.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'cd3359f3-5c52-465c-94cd-46d304141c29';

