-- в”Ђв”Ђ Tito в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
UPDATE tools SET
  short_description = COALESCE($q$Tito is a fast, design-focused event registration and ticketing platform used by conference and event organizers to sell tickets, manage attendees and handle check-in, charging a simple per-ticket fee instead of a monthly subscription.$q$, short_description),
  pricing_model = COALESCE($q$usage-based$q$, pricing_model),
  starting_price = COALESCE($q$Free (3% fee on paid tickets)$q$, starting_price),
  founded_year = COALESCE(2012, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Dublin, Ireland$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Tito Review 2026: Pricing, Features and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Tito is a per-ticket-fee event registration platform. See Tito's pricing, features, check-in tools and how it compares to Eventbrite and other alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Tito is an event registration and ticketing platform built by Team Tito, a small, self-funded, design-led software company based in Dublin, Ireland. It began as a side project started by developer Paul Campbell in 2012, reportedly while working alongside Paddy Cosgrave, later the founder of the Web Summit conference series, and moved into public beta in April 2013 after processing an initial private beta workload of over one million US dollars in ticket sales. Tito has since processed more than one billion US dollars in ticket sales for organizers worldwide. The platform lets event organizers create registration pages, sell tickets, collect custom attendee information, manage waitlists and discount codes, run check-in on event day, and export financial reports, positioning itself as a faster, more flexible and less cluttered alternative to larger platforms like Eventbrite. Rather than charging a monthly subscription or platform fee, Tito uses a simple usage-based pricing model: creating an account and running a free event costs nothing, and paid events are charged a 3 percent fee per ticket sold, reduced to roughly 2.5 percent for qualifying charity, non-profit or community events, with a fee cap of 25 euros per ticket for higher-priced tickets. Ticket buyers pay through Stripe or PayPal, which charge their own separate transaction processing fees on top of Tito's platform fee, and payouts are typically deposited to the organizer's bank account within a few business days of the sale via the connected payment processor. Tito supports payment processing in 139 currencies, making it usable by organizers in most countries where Stripe or PayPal operate. It is frequently chosen by tech conferences, meetups and community events that value a clean, fast checkout experience and transparent, pay-as-you-sell pricing over a flat monthly software fee.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'a182b645-3634-449e-9ec3-d34c77f3ab09';

